      const tx = this.db.transaction(STORE_AVATARS, 'readwrite');
      const req = tx.objectStore(STORE_AVATARS).delete(key);
      req.onsuccess = () => resolve();
      req.onerror = () => reject(new Error(`删除失败`));
    });
  }

