            const jsonStr = new TextDecoder('utf-8').decode(bytes);
            const data = JSON.parse(jsonStr);
            console.log('[堕落之路初始化] ' + dataName + ' 解码成功');
            return data;
        } catch (e) {
            console.error('[堕落之路初始化] ' + dataName + ' 解码失败:', e);
            return null;
        }
    }

    const EMBEDDED_TEMPLATE = decodeEmbeddedData(EMBEDDED_TEMPLATE_BASE64, '数据库模板');

    document.getElementById('startButton').addEventListener('click', async function() {
        const button = this;
        const statusMsg = document.getElementById('statusMessage');

        button.disabled = true;
        button.textContent = '初始化中...';

        try {
            if (!EMBEDDED_TEMPLATE) {
                console.error('[堕落之路初始化] 数据库模板未配置');
                button.textContent = '⛧ 开始堕落之路';
                button.disabled = false;
                return;
            }

            if (window.parent && window.parent.AutoCardUpdaterAPI && window.parent.AutoCardUpdaterAPI.initGameSession) {
                const result = await window.parent.AutoCardUpdaterAPI.initGameSession({}, {
                    injectTemplate: true,
                    loadPreset: false,
                    templateData: EMBEDDED_TEMPLATE
                });

                if (!result.success) {
                    console.error('[堕落之路初始化] 数据注入失败:', result.message);
                    button.textContent = '⛧ 开始堕落之路';
                    button.disabled = false;
                    return;
                }

                console.log('[堕落之路初始化] 表格数据注入成功');
                sendToTavern('开始');
                statusMsg.classList.add('show');
                button.textContent = '已开始 ⛧';

                setTimeout(() => { statusMsg.classList.remove('show'); }, 3000);
            } else {
                console.warn('[堕落之路初始化] AutoCardUpdaterAPI 接口不可用，请确保在酒馆扩展中打开此页面');
                button.textContent = '⛧ 开始堕落之路';
                button.disabled = false;
            }
        } catch (e) {
            console.error('[堕落之路初始化] 初始化失败:', e);
            button.textContent = '⛧ 开始堕落之路';
            button.disabled = false;
        }
    });

    function sendToTavern(message) {
        try {
            if (parent.document.getElementById('send_textarea')) {
                const textarea = parent.document.getElementById('send_textarea');
                const sendButton = parent.document.getElementById('send_but');

                if (textarea && sendButton) {
                    textarea.value = message;
                    sendButton.click();
                    console.log('[堕落之路初始化] 消息已发送到酒馆');
                } else {
                    console.error('[堕落之路初始化] 无法找到酒馆输入框或发送按钮');
                }
            } else {
                console.warn('[堕落之路初始化] 无法连接到酒馆');
            }
        } catch (e) {
            console.error('[堕落之路初始化] 发送消息失败:', e);
        }
    }
