<div class="container">
  <div class="header">🎯 下一步行动建议</div>
  <div id="options-container"></div>
</div>

<script>
const rawData = `$1`;

function parseActionSuggestions(data) {
  const lines = data.split('\n').map(l => l.trim());
  const suggestions = [];
  let parsing = false;

  lines.forEach(line => {
    if (line.startsWith('下一步行动建议')) { parsing = true; return; }
    if (parsing && line.startsWith('-')) {
      const match = line.match(/-\s*【(.*?)】\s*:\s*["']?(.*?)["']?$/);
      if(match){
        const label = match[1].trim();
        const desc = match[2].trim();
        suggestions.push({ label, desc });
      }
    }
  });
  return suggestions;
}

const actions = parseActionSuggestions(rawData);
const container = document.getElementById('options-container');

actions.forEach(({label, desc}) => {
  const div = document.createElement('div');
  div.className = 'option';
  div.innerHTML = `<span class="option-label">【${label}】</span> <span class="option-desc">${desc}</span>`;
div.addEventListener('click', () => {
  const toSend = desc;

  // 尝试把文本追加到聊天输入框
  try {
    // 这里用 parent.document 查找输入框
    const $textarea = window.parent?.document.querySelector('#send_textarea') || 
                      document.querySelector('textarea');

    if ($textarea) {
      const currentContent = $textarea.value || '';
      const separator = currentContent.trim() ? '\n' : '';
      $textarea.value = currentContent + separator + toSend.trim();

      // 触发 input 事件，让前端监听器响应变化
      const event = new Event('input', { bubbles: true });
      $textarea.dispatchEvent(event);
    } else {
      // 找不到输入框，回退到控制台输出
      console.log('要发送的文本:', toSend);
      alert('无法找到输入框，已复制文本到剪贴板:\n' + toSend);
      try { navigator.clipboard.writeText(toSend); } catch (e) {}
    }
  } catch (e) {
    console.warn('追加到输入框失败', e);
    console.log('要发送的文本:', toSend);
  }

  // 视觉反馈
  div.style.background = 'rgba(187,134,252,0.25)';
  div.style.borderColor = 'rgba(187,134,252,0.5)';
});

  container.appendChild(div);
});

if(actions.length===0){
  container.innerHTML='<div style="text-align:center;color:#777;">（无可用行动建议）</div>';
}
</script>
</body>
</html>

