<html lang="zh-CN">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>状态栏</title>
<style>
@import url('https://fonts.googleapis.com/css2?family=Noto+Sans+SC:wght@300;400;500;700&family=Noto+Serif+SC:wght@400;600;700&display=swap');
*{margin:0;padding:0;box-sizing:border-box}
:root{
  --bg:#f5f0f8;--bg-card:#fff;--bg-inset:#ede7f2;--bg-elevated:#f9f6fc;
  --border:rgba(180,120,200,0.15);--border-strong:rgba(180,120,200,0.3);
  --text:#3a2a4a;--text-sub:#7a6a8a;--text-muted:#b0a0b8;
  --accent:#e870a0;--accent-light:#f0a0c0;--accent-glow:rgba(232,112,160,0.15);
  --gold:#c8a040;--rose:#d06070;--silver:#8090a0;--crimson:#a03040;--void:#3a1020;
  --bar-bg:rgba(180,120,200,0.1);--shadow:0 2px 12px rgba(100,60,120,0.08);
}
[data-stage="2"]{
  --bg:#f0e8f5;--bg-card:#faf5ff;--bg-inset:#ece2f5;--bg-elevated:#f5eefa;
  --border:rgba(160,80,200,0.18);--border-strong:rgba(160,80,200,0.35);
  --text:#3a2848;--text-sub:#7a6090;--text-muted:#a08ab5;
  --accent:#c070d0;--accent-light:#d8a0e5;--accent-glow:rgba(192,112,208,0.15);
  --gold:#b090d0;--rose:#c060a0;--silver:#7080a0;--crimson:#a04080;--void:#4a1850;
  --bar-bg:rgba(160,80,200,0.1);--shadow:0 2px 12px rgba(80,40,120,0.1);
}
[data-stage="3"]{
  --bg:#281a3a;--bg-card:#302045;--bg-inset:#221535;--bg-elevated:#38264e;
  --border:rgba(140,60,200,0.18);--border-strong:rgba(140,60,200,0.35);
  --text:#e8daf0;--text-sub:#b098c0;--text-muted:#786088;
  --accent:#a050d0;--accent-light:#c080e8;--accent-glow:rgba(160,80,208,0.15);
  --gold:#c89040;--rose:#d06080;--silver:#90a0b8;--crimson:#c04050;--void:#200828;
  --bar-bg:rgba(140,60,200,0.12);--shadow:0 2px 16px rgba(30,10,50,0.5);
}
[data-stage="4"]{
  --bg:#12101e;--bg-card:#181428;--bg-inset:#100c1a;--bg-elevated:#1e1830;
  --border:rgba(150,60,180,0.14);--border-strong:rgba(150,60,180,0.28);
  --text:#d4c4e0;--text-sub:#9078a0;--text-muted:#604868;
  --accent:#b060d8;--accent-light:#c880e8;--accent-glow:rgba(176,96,216,0.12);
  --gold:#c08838;--rose:#c85878;--silver:#707888;--crimson:#b83850;--void:#1a0820;
  --bar-bg:rgba(150,60,180,0.1);--shadow:0 2px 16px rgba(20,10,30,0.5);
}
[data-stage="5"]{
  --bg:#1a1028;--bg-card:#201530;--bg-inset:#160e22;--bg-elevated:#261a38;
  --border:rgba(160,80,220,0.15);--border-strong:rgba(160,80,220,0.3);
  --text:#e0d0f0;--text-sub:#a088b8;--text-muted:#6a5080;
  --accent:#b060e0;--accent-light:#c890f0;--accent-glow:rgba(176,96,224,0.15);
  --gold:#d0a040;--rose:#e06080;--silver:#80a0c0;--crimson:#d04050;--void:#2a0820;
  --bar-bg:rgba(160,80,220,0.1);--shadow:0 2px 16px rgba(40,10,60,0.4);
}
body{font-family:'Noto Sans SC',sans-serif;background:#060308;color:var(--text);padding:0;font-size:13px;line-height:1.5;-webkit-font-smoothing:antialiased;transition:all 0.8s cubic-bezier(0.22,1,0.36,1)}
.hud{width:100%;background:var(--bg-card);border-radius:0;overflow:hidden;box-shadow:var(--shadow);transition:all 0.8s cubic-bezier(0.22,1,0.36,1)}
.topbar{display:flex;justify-content:space-between;align-items:center;padding:8px 16px;background:var(--bg-card);font-size:11px;color:var(--text-sub);transition:all 0.8s}
.topbar .loc{display:flex;align-items:center;gap:6px}
.topbar .loc::before{content:'';width:5px;height:5px;border-radius:50%;background:var(--accent);box-shadow:0 0 6px var(--accent);transition:all 0.8s}
.topbar .time{font-family:'Noto Serif SC',serif;color:var(--text-muted);letter-spacing:0.5px}
.hero{position:relative;width:100%;background:var(--bg-card);cursor:pointer;overflow:hidden;transition:all 0.8s}
.hero img{width:100%;max-height:400px;object-fit:contain;display:block;transition:transform 0.5s}
.hero:hover img{transform:scale(1.015)}
.hero-placeholder{width:100%;min-height:120px;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:10px}
.hero-placeholder .ring{width:52px;height:52px;border-radius:50%;border:1.5px solid var(--accent);display:flex;align-items:center;justify-content:center;font-family:'Noto Serif SC',serif;font-size:18px;font-weight:600;color:var(--accent);transition:all 0.8s}
.hero-placeholder .sub{font-size:10px;color:var(--text-muted);letter-spacing:2px}
.hero-grad{position:absolute;bottom:0;left:0;right:0;height:40%;background:linear-gradient(to top,var(--bg-card) 5%,transparent 100%);pointer-events:none;transition:all 0.8s}
.hero-info{position:absolute;bottom:0;left:0;right:0;padding:0 14px 10px;z-index:1}
.hero-name{font-family:'Noto Serif SC',serif;font-size:20px;font-weight:700;letter-spacing:2px;text-shadow:0 2px 10px rgba(0,0,0,0.5);transition:all 0.5s}
.hero-en{font-size:10px;color:var(--text-muted);letter-spacing:1px;font-family:'Noto Serif SC',serif}
.hero-meta{display:flex;align-items:center;gap:8px;margin-top:4px}
.stage-chip{padding:2px 8px;border-radius:4px;font-size:9px;font-weight:500;letter-spacing:0.5px;border:1px solid var(--border-strong);color:var(--accent);background:var(--accent-glow);transition:all 0.8s}
.magic-tag{font-size:10px;color:var(--text-sub);font-weight:500;letter-spacing:0.5px}
.hero .hint{position:absolute;top:10px;right:12px;font-size:9px;color:rgba(128,128,128,0.5);opacity:0;transition:opacity 0.2s;z-index:2}
.hero:hover .hint{opacity:1}
.corp{padding:10px 16px 6px;transition:all 0.8s}
.corr-head{display:flex;justify-content:space-between;align-items:baseline;margin-bottom:6px}
.corr-label{font-size:10px;color:var(--text-muted);letter-spacing:1.5px}
.corr-val{font-family:'Noto Serif SC',serif;font-size:22px;font-weight:700;color:var(--accent);transition:all 0.5s}
.bar-track{height:6px;background:var(--bar-bg);border-radius:3px;overflow:hidden;transition:all 0.8s}
.bar-fill{height:100%;border-radius:3px;transition:width 0.6s cubic-bezier(0.22,1,0.36,1),background 0.8s}
[data-stage="1"] .bar-fill{background:linear-gradient(90deg,#e0a0c0,var(--accent))}
[data-stage="2"] .bar-fill{background:linear-gradient(90deg,#a070c0,#c080e0)}
[data-stage="3"] .bar-fill{background:linear-gradient(90deg,#7040a0,var(--accent))}
[data-stage="4"] .bar-fill{background:linear-gradient(90deg,#7838a0,var(--accent))}
[data-stage="5"] .bar-fill{background:linear-gradient(90deg,#8040a0,var(--accent))}
.tri{display:grid;grid-template-columns:repeat(5,1fr);gap:1px;margin:8px 16px;background:var(--border);border-radius:8px;overflow:hidden;transition:all 0.8s}
.tri-cell{background:var(--bg-card);padding:8px 6px;text-align:center;transition:all 0.8s}
.tri-cell .tl{font-size:9px;color:var(--text-muted);letter-spacing:0.3px;margin-bottom:2px}
.tri-cell .tv{font-size:14px;font-weight:700;font-variant-numeric:tabular-nums;color:var(--accent);transition:all 0.5s}
.pills{display:flex;gap:6px;padding:0 16px;margin-bottom:8px;flex-wrap:wrap}
.pill{padding:4px 10px;border-radius:4px;font-size:11px;background:var(--bg-elevated);border:1px solid var(--border);color:var(--text-sub);display:flex;align-items:center;gap:6px;transition:all 0.8s}
.pill .d{width:5px;height:5px;border-radius:50%;background:var(--accent);box-shadow:0 0 4px var(--accent-glow);transition:all 0.8s}
.body{margin:0 16px 8px;padding:10px 12px;background:var(--bg-elevated);border-radius:8px;border:1px solid var(--border);transition:all 0.8s}
.body-t{font-size:10px;color:var(--accent);letter-spacing:1px;margin-bottom:8px;display:flex;align-items:center;gap:6px;transition:all 0.8s}
.body-t::before{content:'';width:8px;height:1.5px;background:var(--accent);border-radius:1px;transition:all 0.8s}
.br{display:flex;align-items:center;gap:8px;margin-bottom:5px}
.br:last-child{margin-bottom:0}
.br .bl{font-size:11px;color:var(--text-sub);width:28px;flex-shrink:0}
.br .bt{flex:1;height:4px;background:var(--bar-bg);border-radius:2px;overflow:hidden;transition:all 0.8s}
.br .bf{height:100%;border-radius:2px;background:linear-gradient(90deg,var(--accent),var(--rose));transition:width 0.5s,background 0.8s}
.br .bv{font-size:10px;color:var(--text-muted);width:28px;text-align:right;font-variant-numeric:tabular-nums}
.thought{margin:0 16px 8px;padding:8px 12px;border-left:2px solid var(--accent);background:var(--accent-glow);border-radius:0 6px 6px 0;font-size:11px;color:var(--text-sub);font-style:italic;line-height:1.6;transition:all 0.8s}
.sep{height:1px;margin:0 14px 8px;background:linear-gradient(90deg,transparent,var(--border-strong),transparent);transition:all 0.8s}
.allies{display:grid;grid-template-columns:1fr 1fr;gap:6px;padding:0 16px 10px}
.ally{padding:10px;background:var(--bg-elevated);border-radius:8px;border:1px solid var(--border);transition:all 0.8s}
.ally-top{display:flex;align-items:center;gap:8px;margin-bottom:6px}
.ally-av{width:26px;height:26px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:11px;font-weight:600;color:#fff;flex-shrink:0;transition:all 0.5s}
[data-stage="1"] .a1{background:linear-gradient(135deg,#6090c0,#80b0e0)}
[data-stage="2"] .a1{background:linear-gradient(135deg,#5070a0,#7090c0)}
[data-stage="3"] .a1{background:linear-gradient(135deg,#405080,#6070a0)}
[data-stage="4"] .a1{background:linear-gradient(135deg,#303050,#505070)}
[data-stage="5"] .a1{background:linear-gradient(135deg,#202030,#404050)}
.a2{background:linear-gradient(135deg,#c08030,#e0a850)}
.ally-nm{font-size:12px;font-weight:500}
.ally-role{font-size:9px;color:var(--text-muted)}
.ally-st{display:flex;gap:8px;font-size:10px;color:var(--text-muted)}
.ally-st b{font-weight:600;color:var(--text-sub);font-variant-numeric:tabular-nums}
.ally-th{margin-top:5px;padding-top:5px;border-top:1px solid var(--border);font-size:10px;color:var(--text-muted);font-style:italic;transition:all 0.8s}
.rels{margin:0 16px 10px;padding:8px 10px;background:var(--bg-elevated);border-radius:8px;border:1px solid var(--border);transition:all 0.8s}
.rels-t{font-size:9px;color:var(--text-muted);letter-spacing:1.5px;margin-bottom:5px}
.rel-r{display:flex;justify-content:space-between;font-size:11px;color:var(--text-sub);padding:3px 0;transition:all 0.8s}
.rel-r+.rel-r{border-top:1px solid var(--border)}
.rel-v{color:var(--accent);font-weight:500;font-variant-numeric:tabular-nums}
</style>
</head>
<body>
<div class="hud" id="hud" data-stage="1"></div>
<script>
var S={loc:'城市废墟',time:'傍晚',day:'1',z:{cor:0,mark:0,mag:50,cum:0,prog:0,res:80,sem:0,ms:'无',out:'樱华学园制服',state:'正义坚定',body:{b:0,v:0,c:0,bd:'无变化',vd:'无变化',cd:'无变化'}},a1:{bond:0,th:'',mag:60,hp:80},a2:{bond:0,th:'',mag:50,hp:75},rels:[]};
var W={groups:{1:'雫-阶段一服装',2:'雫-阶段二服装',3:'雫-阶段三服装',4:'雫-阶段四服装',5:'雫-阶段五服装'},slot:{g:null,i:-1,u:null},api:null,av:null,ok:false,a1u:null,a2u:null};
function getAutoCardAPI(){if(typeof parent!=='undefined'&&parent.AutoCardUpdaterAPI)return parent.AutoCardUpdaterAPI;if(window.AutoCardUpdaterAPI)return window.AutoCardUpdaterAPI;return null}
function getCGAPI(){if(typeof window!=='undefined'&&window.top&&window.top.BubbleCG)return window.top.BubbleCG;return null}
function stageInfo(v){if(v<=20)return{i:1,l:'清醒克制'};if(v<=40)return{i:2,l:'自我欺骗'};if(v<=60)return{i:3,l:'灵肉拉锯'};if(v<=80)return{i:4,l:'旧我葬礼'};return{i:5,l:'彻底堕落'}};function bodyLabel(v){if(v<=0)return'未变化';if(v<=20)return'轻微胀大';if(v<=40)return'明显增大';if(v<=60)return'持续膨胀';if(v<=80)return'重度改造';return'完全改造'}
async function initW(){W.api=getCGAPI();W.ok=!!W.api;if(typeof window!=='undefined'&&window.top&&window.top.BubbleAvatar)W.av=window.top.BubbleAvatar;else W.av=null}
async function loadW(si){var s=W.slot,gn=W.groups[si];if(s.g===gn&&s.u)return;s.g=gn;s.u=null;if(!W.ok)return;try{s.u=await W.api.getRandomImage(gn);s.i=-1}catch(e){}}
async function cycleW(){if(!W.ok)return;var s=W.slot;if(!s.g)return;try{s.u=await W.api.getRandomImage(s.g);s.i=-1}catch(e){s.u=null}updImg()}
function updImg(){var img=document.getElementById('hImg'),ph=document.getElementById('hPh');if(W.slot.u){if(img){img.src=W.slot.u;img.style.display='block'}if(ph)ph.style.display='none'}}
async function loadTableData(){var api=getAutoCardAPI();if(!api){renderHUD();return}try{var raw=await api.exportTableAsJson();var tables=typeof raw==='string'?JSON.parse(raw):raw;parseTables(tables);renderHUD()}catch(e){console.error('[状态栏]',e);renderHUD()}}
function parseTables(tables){for(var uid in tables){var sh=tables[uid];if(!sh||!sh.content||sh.content.length<2)continue;var h=sh.content[0],rows=sh.content.slice(1);var g=function(r,c){var i=h.indexOf(c);return i!==-1&&i<r.length?r[i]:undefined};
if(sh.name==='重要角色表'){rows.forEach(function(r){var n=g(r,'姓名'),s=g(r,'当前状态');if(n==='望月雫'&&s)S.z.state=s;if(n==='白鸟绫乃'&&s)S.a1.th=s;if(n==='绯樱凛'&&s)S.a2.th=s})}
if(sh.name==='当前状态表'&&rows.length>0){S.loc=g(rows[0],'当前位置')||S.loc;S.time=g(rows[0],'当前时间')||S.time;S.day=g(rows[0],'天数')||S.day}
if(sh.name==='主角状态表'){rows.forEach(function(r){var a=g(r,'属性'),v=g(r,'数值'),n=parseInt(v)||0;if(a==='堕落进度')S.z.cor=n;if(a==='淫纹等级')S.z.mark=n;if(a==='魔力值')S.z.mag=n;if(a==='高潮次数')S.z.cum=n;if(a==='堕落进度')S.z.prog=n;if(a==='精神抵抗值')S.z.res=n;if(a==='精液吸收量')S.z.sem=n;if(a==='淫纹状态')S.z.ms=v;if(a==='服装状态')S.z.out=v})}
if(sh.name==='身体变化表'){rows.forEach(function(r){var p=g(r,'部位'),v=parseInt(g(r,'变化值'))||0,d=g(r,'变化描述')||'';if(p==='胸部变化'){S.z.body.b=v;S.z.body.bd=d||bodyLabel(v)}if(p==='小穴变化'){S.z.body.v=v;S.z.body.vd=d||bodyLabel(v)}if(p==='阴蒂变化'){S.z.body.c=v;S.z.body.cd=d||bodyLabel(v)}})}
if(sh.name==='队友绫乃状态表'){rows.forEach(function(r){var a=g(r,'属性'),v=g(r,'数值'),n=parseInt(v)||0;if(a==='友情度')S.a1.bond=n;if(a==='心里话')S.a1.th=v;if(a==='魔力值')S.a1.mag=n;if(a==='体力值')S.a1.hp=n})}
if(sh.name==='队友凛状态表'){rows.forEach(function(r){var a=g(r,'属性'),v=g(r,'数值'),n=parseInt(v)||0;if(a==='友情度')S.a2.bond=n;if(a==='心里话')S.a2.th=v;if(a==='魔力值')S.a2.mag=n;if(a==='体力值')S.a2.hp=n})}
if(sh.name==='关系状态表'){S.rels=rows.map(function(r){return{c1:g(r,'角色1'),c2:g(r,'角色2'),int:g(r,'亲密值')}}).filter(function(r){return r.c1&&r.c2})}}}
function renderHUD(){var z=S.z,si=stageInfo(z.cor),s=W.slot;var hc=s.u?'<img id="hImg" src="'+s.u+'" style="display:block"/>':'<div class="hero-placeholder" id="hPh"><div class="ring">雫</div><div class="sub">WARDROBE</div></div>';var a1av=W.a1u?'<img src="'+W.a1u+'" style="width:100%;height:100%;object-fit:cover;border-radius:50%"/>':'<span>绫</span>';var a2av=W.a2u?'<img src="'+W.a2u+'" style="width:100%;height:100%;object-fit:cover;border-radius:50%"/>':'<span>凛</span>';var hud=document.getElementById('hud');hud.setAttribute('data-stage',si.i);var h='<div class="topbar"><div class="loc">'+S.loc+'</div><div class="time">'+S.time+' / DAY '+S.day+'</div></div><div class="hero" id="heroA">'+hc+'<div class="hero-grad"></div><div class="hero-info"><div class="hero-name">望月雫</div><div class="hero-en">Mochizuki Shizuku</div><div class="hero-meta"><span class="stage-chip">'+si.l+'</span><span class="magic-tag">MAG '+z.mag+'</span></div></div><div class="hint">click</div></div><div class="corr"><div class="corr-head"><span class="corr-label">堕落阶段</span><span class="corr-val">'+z.cor+'%</span></div><div class="bar-track"><div class="bar-fill" style="width:'+z.cor+'%"></div></div></div><div class="tri"><div class="tri-cell"><div class="tl">堕落进度</div><div class="tv">'+z.prog+'%</div></div><div class="tri-cell"><div class="tl">淫纹等级</div><div class="tv">'+z.mark+'%</div></div><div class="tri-cell"><div class="tl">精神抵抗</div><div class="tv">'+z.res+'%</div></div><div class="tri-cell"><div class="tl">高潮次数</div><div class="tv">'+z.cum+'</div></div><div class="tri-cell"><div class="tl">精液吸收</div><div class="tv">'+z.sem+'</div></div></div><div class="pills"><div class="pill"><span class="d"></span>淫纹：'+z.ms+'</div><div class="pill"><span class="d"></span>'+z.out+'</div></div><div class="body"><div class="body-t">身体改造 / 不可逆</div><div class="br"><span class="bl">胸部</span><span class="bv" style="flex:1;text-align:left;padding-left:6px;font-size:11px;color:var(--accent)">'+z.body.bd+'</span></div><div class="br"><span class="bl">小穴</span><span class="bv" style="flex:1;text-align:left;padding-left:6px;font-size:11px;color:var(--accent)">'+z.body.vd+'</span></div><div class="br"><span class="bl">阴蒂</span><span class="bv" style="flex:1;text-align:left;padding-left:6px;font-size:11px;color:var(--accent)">'+z.body.cd+'</span></div></div><div class="thought">'+z.state+'</div><div class="sep"></div><div class="allies"><div class="ally"><div class="ally-top"><div class="ally-av a1">'+a1av+'</div><div><div class="ally-nm">白鸟绫乃</div><div class="ally-role">队长</div></div></div><div class="ally-st"><span>MAG <b>'+S.a1.mag+'</b></span><span>HP <b>'+S.a1.hp+'</b></span><span>BOND <b>'+S.a1.bond+'</b></span></div><div class="ally-th">'+S.a1.th+'</div></div><div class="ally"><div class="ally-top"><div class="ally-av a2">'+a2av+'</div><div><div class="ally-nm">绯樱凛</div><div class="ally-role">学妹</div></div></div><div class="ally-st"><span>MAG <b>'+S.a2.mag+'</b></span><span>HP <b>'+S.a2.hp+'</b></span><span>BOND <b>'+S.a2.bond+'</b></span></div><div class="ally-th">'+S.a2.th+'</div></div></div>';
if(S.rels.length>0){h+='<div class="rels"><div class="rels-t">RELATIONSHIPS</div>';S.rels.forEach(function(r){h+='<div class="rel-r"><span>'+r.c1+' / '+r.c2+'</span><span class="rel-v">'+r.int+'%</span></div>'});h+='</div>'}
